# shapes.spy - Abstract shape classes and interfaces

interface IArea:
    def area(self) -> float: ...

interface IPerimeter:
    def perimeter(self) -> float: ...

@abstract
class Shape:
    name: str
    shape_id: int
    @static next_id: int = 1

    def __init__(self, name: str):
        self.name = name
        self.shape_id = Shape.next_id
        Shape.next_id = Shape.next_id + 1

    @abstract
    def describe(self) -> str: ...

class Rectangle(Shape, IArea, IPerimeter):
    width: float
    height: float

    def __init__(self, width: float, height: float):
        super().__init__("Rectangle")
        self.width = width
        self.height = height

    def describe(self) -> str:
        return self.name + " " + str(self.shape_id)

    def area(self) -> float:
        return self.width * self.height

    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

class Circle(Shape, IArea, IPerimeter):
    radius: float
    const PI: float = 3.14159

    def __init__(self, radius: float):
        super().__init__("Circle")
        self.radius = radius

    def describe(self) -> str:
        return self.name + " " + str(self.shape_id)

    def area(self) -> float:
        return Circle.PI * self.radius * self.radius

    def perimeter(self) -> float:
        return 2.0 * Circle.PI * self.radius

enum Color:
    RED = 1
    GREEN = 2
    BLUE = 3

def calculate_total_area(shapes: list[Shape]) -> float:
    total: float = 0.0
    for s in shapes:
        total = total + s.area()
    return total

