# collections.spy - Shape collections with inheritance

from shapes import Shape, Rectangle, Color
from utils import Point

@abstract
class ShapeContainer(Shape):
    contents: list[Shape]

    def __init__(self, name: str):
        super().__init__(name)
        self.contents = []

    def add(self, s: Shape):
        self.contents.append(s)

    @abstract
    def capacity(self) -> int: ...

class Box(Rectangle, ShapeContainer):
    depth: float

    def __init__(self, w: float, h: float, d: float):
        Rectangle.__init__(self, w, h)
        ShapeContainer.__init__(self, "Box")
        self.depth = d

    def capacity(self) -> int:
        return len(self.contents)

    def volume(self) -> float:
        return self.width * self.height * self.depth

    def describe(self) -> str:
        return "Box(" + str(self.capacity()) + " items)"

class DrawableRectangle(Rectangle):
    color: Color
    position: Point

    def __init__(self, w: float, h: float, c: Color, pos: Point):
        super().__init__(w, h)
        self.color = c
        self.position = pos

    def describe(self) -> str:
        base: str = super().describe()
        return "Drawable" + base + " at " + str(self.position.x)

def create_bounded_shape(dim: Dimension, color: Color) -> DrawableRectangle:
    return DrawableRectangle(dim.width, dim.height, color, Point(0.0, 0.0))
